import os
import numpy as np
import cv2
from flask import Flask, request, jsonify
import face_recognition
import pickle
from typing import Dict, List, Tuple
import hashlib
import hmac
from datetime import datetime, timedelta
import secrets

app = Flask(__name__)

# Security configuration
API_KEY = os.environ.get('API_KEY', secrets.token_hex(32))
MAX_REQUESTS_PER_MINUTE = 10
NOISE_SCALE = 0.05
MIN_CONFIDENCE_THRESHOLD = 0.3

# Rate limiting storage
request_log = {}

class SecureFaceRecognitionSystem:
    def __init__(self, training_data_path='employee_photos', model_path='face_model.pkl'):
        self.training_data_path = training_data_path
        self.model_path = model_path
        self.known_face_encodings = []
        self.known_face_names = []
        self.face_id_map = {}
        
    def train_model(self):
        """Train the face recognition model on employee photos"""
        if not os.path.exists(self.training_data_path):
            os.makedirs(self.training_data_path)
            print(f"Created directory: {self.training_data_path}")
            return
        
        employee_dirs = [d for d in os.listdir(self.training_data_path) 
                        if os.path.isdir(os.path.join(self.training_data_path, d))]
        
        for employee_name in employee_dirs:
            employee_path = os.path.join(self.training_data_path, employee_name)
            image_files = [f for f in os.listdir(employee_path) 
                          if f.lower().endswith(('.jpg', '.jpeg', '.png'))]
            
            for image_file in image_files:
                image_path = os.path.join(employee_path, image_file)
                image = face_recognition.load_image_file(image_path)
                face_encodings = face_recognition.face_encodings(image)
                
                if face_encodings:
                    self.known_face_encodings.append(face_encodings[0])
                    employee_id = hashlib.sha256(employee_name.encode()).hexdigest()[:16]
                    self.known_face_names.append(employee_id)
                    self.face_id_map[employee_id] = employee_name
        
        self.save_model()
        print(f"Model trained with {len(self.known_face_encodings)} face encodings")
    
    def save_model(self):
        """Save the trained model"""
        model_data = {
            'encodings': self.known_face_encodings,
            'names': self.known_face_names,
            'id_map': self.face_id_map
        }
        with open(self.model_path, 'wb') as f:
            pickle.dump(model_data, f)
    
    def load_model(self):
        """Load the trained model"""
        if os.path.exists(self.model_path):
            with open(self.model_path, 'rb') as f:
                model_data = pickle.load(f)
                self.known_face_encodings = model_data['encodings']
                self.known_face_names = model_data['names']
                self.face_id_map = model_data['id_map']
            return True
        return False
    
    def add_differential_privacy_noise(self, probabilities: np.ndarray) -> np.ndarray:
        """Add calibrated noise to prevent model inversion attacks"""
        noise = np.random.laplace(0, NOISE_SCALE, probabilities.shape)
        noisy_probs = probabilities + noise
        noisy_probs = np.clip(noisy_probs, 0, 1)
        noisy_probs = noisy_probs / np.sum(noisy_probs)
        return noisy_probs
    
    def calculate_confidence_distribution(self, face_encoding) -> Dict[str, float]:
        """Calculate confidence scores with privacy protection"""
        if not self.known_face_encodings:
            return {}
        
        face_distances = face_recognition.face_distance(
            self.known_face_encodings, face_encoding
        )
        
        # Convert distances to similarities (inverse relationship)
        similarities = 1 - face_distances
        similarities = np.clip(similarities, 0, 1)
        
        # Aggregate by employee ID
        employee_scores = {}
        for idx, employee_id in enumerate(self.known_face_names):
            if employee_id not in employee_scores:
                employee_scores[employee_id] = []
            employee_scores[employee_id].append(similarities[idx])
        
        # Average scores for each employee
        avg_scores = {emp_id: np.mean(scores) 
                     for emp_id, scores in employee_scores.items()}
        
        # Convert to probability distribution
        total = sum(avg_scores.values())
        if total > 0:
            probabilities = np.array([score / total for score in avg_scores.values()])
        else:
            probabilities = np.ones(len(avg_scores)) / len(avg_scores)
        
        # Add differential privacy noise
        noisy_probabilities = self.add_differential_privacy_noise(probabilities)
        
        # Filter low confidence results
        result = {}
        for idx, (emp_id, _) in enumerate(avg_scores.items()):
            confidence = float(noisy_probabilities[idx])
            if confidence >= MIN_CONFIDENCE_THRESHOLD:
                result[emp_id] = round(confidence, 4)
        
        return result
    
    def recognize_face(self, image_data) -> Dict:
        """Recognize face from image data"""
        nparr = np.frombuffer(image_data, np.uint8)
        image = cv2.imdecode(nparr, cv2.IMREAD_COLOR)
        rgb_image = cv2.cvtColor(image, cv2.COLOR_BGR2RGB)
        
        face_locations = face_recognition.face_locations(rgb_image)
        face_encodings = face_recognition.face_encodings(rgb_image, face_locations)
        
        if not face_encodings:
            return {'error': 'No face detected in image'}
        
        results = []
        for face_encoding in face_encodings:
            confidence_distribution = self.calculate_confidence_distribution(face_encoding)
            results.append({
                'confidence_distribution': confidence_distribution,
                'timestamp': datetime.utcnow().isoformat()
            })
        
        return {'faces': results}


# Initialize the face recognition system
face_system = SecureFaceRecognitionSystem()

def verify_api_key(api_key: str) -> bool:
    """Verify API key using constant-time comparison"""
    return hmac.compare_digest(api_key, API_KEY)

def check_rate_limit(client_id: str) -> bool:
    """Check if client has exceeded rate limit"""
    current_time = datetime.utcnow()
    
    if client_id not in request_log:
        request_log[client_id] = []
    
    # Remove old requests
    request_log[client_id] = [
        req_time for req_time in request_log[client_id]
        if current_time - req_time < timedelta(minutes=1)
    ]
    
    if len(request_log[client_id]) >= MAX_REQUESTS_PER_MINUTE:
        return False
    
    request_log[client_id].append(current_time)
    return True

@app.route('/api/recognize', methods=['POST'])
def recognize():
    """API endpoint for face recognition"""
    api_key = request.headers.get('X-API-Key')
    if not api_key or not verify_api_key(api_key):
        return jsonify({'error': 'Invalid API key'}), 401
    
    client_id = request.remote_addr
    if not check_rate_limit(client_id):
        return jsonify({'error': 'Rate limit exceeded'}), 429
    
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    image_file = request.files['image']
    image_data = image_file.read()
    
    # Validate image size
    if len(image_data) > 10 * 1024 * 1024:  # 10MB limit
        return jsonify({'error': 'Image too large'}), 400
    
    result = face_system.recognize_face(image_data)
    return jsonify(result)

@app.route('/api/train', methods=['POST'])
def train():
    """API endpoint to trigger model training"""
    api_key = request.headers.get('X-API-Key')
    if not api_key or not verify_api_key(api_key):
        return jsonify({'error': 'Invalid API key'}), 401
    
    face_system.train_model()
    return jsonify({'message': 'Model training completed'})

@app.route('/api/health', methods=['GET'])
def health():
    """Health check endpoint"""
    return jsonify({
        'status': 'healthy',
        'model_loaded': len(face_system.known_face_encodings) > 0,
        'num_employees': len(set(face_system.known_face_names))
    })

if __name__ == '__main__':
    # Load existing model or train new one
    if not face_system.load_model():
        print("No existing model found. Training new model...")
        face_system.train_model()
    
    print(f"API Key: {API_KEY}")
    print("Keep this key secure and use it in X-API-Key header")
    
    app.run(host='0.0.0.0', port=5000, debug=False)